import tensorflow as tf
from tensorflow import keras

# ❌ ANTI-PATTERN: Creating new variables inside @tf.function
class CricketScoreTrackerBad(keras.Model):
    def __init__(self):
        super().__init__()
        self.dense = keras.layers.Dense(10)

    @tf.function
    def call(self, inputs):
        # WRONG: Variable created in traced function causes retracing
        self.runs_by_batsman = tf.Variable(tf.zeros(11))  # 11 players
        output = self.dense(inputs)
        return output

# ✅ BEST PRACTICE: Variable definition in __init__, use in call
class CricketScoreTrackerGood(keras.Model):
    def __init__(self):
        super().__init__()
        self.dense = keras.layers.Dense(10)
        # Pre-allocate tracking variables
        self.runs_by_batsman = tf.Variable(
            tf.zeros(11),
            trainable=False,
            name='batsman_runs'
        )

    @tf.function
    def call(self, inputs, batsman_idx=None):
        # Safe: Only updating pre-defined variable
        if batsman_idx is not None:
            runs_scored = self.dense(inputs)
            self.runs_by_batsman[batsman_idx].assign_add(
                tf.reduce_sum(runs_scored)
            )
        return self.dense(inputs)

# ❌ ANTI-PATTERN: Mixing eager and graph execution carelessly
model_bad = CricketScoreTrackerBad()
for batch in range(5):
    # Causes 5 graph retracings—huge performance penalty
    output = model_bad(tf.random.normal((32, 20)))

# ✅ BEST PRACTICE: Single graph trace, reuse across batches
model_good = CricketScoreTrackerGood()
graph_fn = tf.function(model_good.call)
for batch in range(5):
    # Graph traced once, reused 5 times
    output = graph_fn(tf.random.normal((32, 20)))
